        {"method": "GET", "path": "/v1/reports/system", "summary": "Return the unified system report with runtime, AMOS, and software-control sections.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/reports/metrics", "summary": "Return compact observability and operator metrics across runtime, AMOS, maintenance, and software control.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/reports/metrics/history", "summary": "Return persisted observability metric history and trend summaries.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/metrics", "summary": "Return Prometheus-compatible operator metrics exported from SQLite-authoritative snapshots.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/reports/maintenance", "summary": "Return resident maintenance daemon, incident, lease, and recommendation state.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/reports/software-control", "summary": "Return governed software-control manifests, action receipts, replay records, and failure patterns.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory", "summary": "Return the detailed memory state for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/kernel", "summary": "Return the unified AMOS kernel state for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/scopes", "summary": "Return scoped memory records, summaries, and promotions for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/scopes", "summary": "Record a scoped memory item for one task scope.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/scopes/promote", "summary": "Promote a scoped memory item into a broader audience scope.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/scopes/summary", "summary": "Generate a scoped summary such as a handoff or completion summary.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/evidence-pack", "summary": "Assemble an evidence pack for a memory query.", "scopes": ["operator"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/timeline", "summary": "Return timeline reconstruction segments for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/project-state", "summary": "Return reconstructed project state for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/policy", "summary": "Return AMOS memory policy and rollout state for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/maintenance-mode", "summary": "Return maintenance mode and active degradation reasons for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/maintenance-workers", "summary": "Return maintenance worker state visible to one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "GET", "path": "/v1/tasks/{task_id}/memory/maintenance-daemon", "summary": "Return resident maintenance daemon and lease state for one task scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/maintenance-workers/register", "summary": "Register a maintenance worker for resident maintenance cycles.", "scopes": ["runtime-admin"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/maintenance-workers/daemon", "summary": "Run one or more resident maintenance daemon cycles for a worker.", "scopes": ["runtime-admin"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/maintenance-promotions/{recommendation_id}/apply", "summary": "Apply a maintenance controller promotion.", "scopes": ["runtime-admin"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/maintenance-rollouts/{rollout_id}/rollback", "summary": "Rollback a maintenance rollout.", "scopes": ["runtime-admin"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/selective-purge", "summary": "Run selective purge on derived memory layers.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/memory/hard-purge", "summary": "Run hard purge over AMOS-managed durable layers.", "scopes": ["operator"], "sensitive": True},
        {"method": "GET", "path": "/v1/tasks/{task_id}/collaboration", "summary": "Return collaboration ownership, leases, branches, handoffs, and recent events for one task.", "scopes": ["viewer"], "sensitive": False},
