        {"method": "POST", "path": "/v1/tasks/{task_id}/branches", "summary": "Create a collaboration branch for one task.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/tasks/{task_id}/handoff", "summary": "Open an explicit handoff window between collaborators.", "scopes": ["operator"], "sensitive": True},
        {"method": "GET", "path": "/v1/strategy/overview", "summary": "Return strategy feedback, candidates, canaries, and promotion decisions for one scope.", "scopes": ["viewer"], "sensitive": False},
        {"method": "POST", "path": "/v1/strategy/feedback", "summary": "Record a strategy feedback signal for one scope.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/strategy/candidates", "summary": "Create a strategy candidate backed by feedback signals.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/strategy/candidates/{candidate_id}/evaluate", "summary": "Evaluate a strategy candidate.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/strategy/candidates/{candidate_id}/canary", "summary": "Run a canary for a strategy candidate.", "scopes": ["operator"], "sensitive": True},
        {"method": "POST", "path": "/v1/strategy/candidates/{candidate_id}/promote", "summary": "Promote a strategy candidate after review and canary checks.", "scopes": ["operator"], "sensitive": True},
